import pandas as pd

def analyze_dna_sequences(samples: pd.DataFrame) -> pd.DataFrame:
    """
    Identifies DNA sequences with specific patterns.

    Args:
        samples (pd.DataFrame): A DataFrame with columns 'sample_id', 'dna_sequence', and 'species'.

    Returns:
        pd.DataFrame: A DataFrame with the original columns plus boolean columns indicating the presence
                      of each pattern ('has_start', 'has_stop', 'has_agat', 'has_ggg'), ordered by 'sample_id'.
    """

    def has_start_codon(sequence: str) -> bool:
        return sequence.startswith('ATG')

    def has_stop_codon(sequence: str) -> bool:
        return sequence.endswith(('TAA', 'TAG', 'TGA'))

    def has_agat_motif(sequence: str) -> bool:
        return 'AGAT' in sequence

    def has_consecutive_gs(sequence: str) -> bool:
        return 'GGG' in sequence

    samples['has_start'] = samples['dna_sequence'].apply(has_start_codon).astype(int)
    samples['has_stop'] = samples['dna_sequence'].apply(has_stop_codon).astype(int)
    samples['has_agat'] = samples['dna_sequence'].apply(has_agat_motif).astype(int)
    samples['has_ggg'] = samples['dna_sequence'].apply(has_consecutive_gs).astype(int)

    return samples.sort_values(by='sample_id')
