def find_orf(dna_sequence):
    """
    Finds Open Reading Frames (ORFs) in a DNA sequence.

    Args:
        dna_sequence: The DNA sequence to analyze (string).

    Returns:
        A list of ORFs found in the sequence. Each ORF is a tuple:
        (start_position, end_position, sequence).
        Returns an empty list if no ORFs are found.
    """

    orfs = []
    for frame in range(3):
        start = frame
        while start < len(dna_sequence) - 2:
            if dna_sequence[start:start + 3] == 'ATG':
                end = start + 3
                while end < len(dna_sequence) - 2:
                    codon = dna_sequence[end:end + 3]
                    if codon in ['TAA', 'TAG', 'TGA']:
                        orfs.append((start + 1, end + 3, dna_sequence[start:end + 3]))
                        start = end + 3  # Move to the next possible start
                        break
                    end += 3
                else:
                    start += 3 # No stop codon found, move to next possible start
            else:
                start += 3
    return orfs

